{"code":"import json
import math

# Load mapping
with open(locals()['var_function-call-12505133434784321186'], 'r') as f:
    mapping_data = json.load(f)
    barcode_histology_map = mapping_data['mapping']

# Load molecular data
with open(locals()['var_function-call-12787186230160490911'], 'r') as f:
    molecular_data = json.load(f)

# Process
histology_values = {}

for record in molecular_data:
    barcode = record.get('ParticipantBarcode')
    val_str = record.get('normalized_count')

    if barcode in barcode_histology_map and val_str is not None:
        try:
            val = float(val_str)
        except ValueError:
            continue

        histology = barcode_histology_map[barcode]

        # Log10 transformation
        log_val = math.log10(val + 1)

        if histology not in histology_values:
            histology_values[histology] = []
        histology_values[histology].append(log_val)

# Compute averages
averages = {}
for hist, vals in histology_values.items():
    if len(vals) > 0:
        avg = sum(vals) / len(vals)
        averages[hist] = avg

# Format results
formatted_results = {k: round(v, 4) for k, v in averages.items()}

print("__RESULT__:")
print(json.dumps(formatted_results))"}

